import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Shape / skeleton
  it.todo("an empty steps array returns an empty results array");

  // Quoting — main items
  it.todo("a quote for a single plain sword returns base premium plus processing fee");
  it.todo("a quote for several main items sums their base premiums");

  // Quoting — components
  it.todo("a quote for a single component uses the per-component base premium");
  it.todo("a quote for three alike components uses the bundle premium of 60 G");

  // Quoting — per-item risk surcharges
  it.todo("cursed items add a 50% risk surcharge");
  it.todo("items with enchantment >= 5 add a 30% risk surcharge");

  // Quoting — customer-level adjustments
  it.todo("long-standing customers (>= 2 years with MHPCO) receive a 20% loyalty discount");
  it.todo("the first contract carries a 10% initial assessment surcharge");
  it.todo("each contract after the first receives a 15% discount");

  // Quoting — rounding
  it.todo("the premium is rounded up to whole G in MHPCO's favor");

  // Claims — basic
  it.todo("a claim subtracts a 100 G deductible from the damage amount");
  it.todo("the total payout per policy is capped at twice the insurance sum");
  it.todo("damage to items with enchantment >= 8 is reimbursed at 50%");
  it.todo("damage to dragon-material items is fully reimbursed (ignoring deductible reduction effects? deductible still applies)");
  it.todo("remainingCap decreases across successive claims on the same policy");
});

