import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Shape / skeleton
  it("an empty steps array returns an empty results array", () => {
    const out = runScenario({ customer: { yearsWithMHPCO: 0 }, steps: [] });
    expect(out).toEqual({ results: [] });
  });

  // Quoting — main items
  it("a quote for a single plain sword (brand-new customer, first contract) returns 115 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] },
      ],
    });
    // 100 (sword base) × 1.10 (first contract) = 110 + 5 (fee) = 115
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("a quote for several main items sums their base premiums", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 1, cursed: false },
            { type: "amulet", material: "silver", enchantment: 1, cursed: false },
          ],
        },
      ],
    });
    // (100 + 60) × 1.10 + 5 = 176 + 5 = 181
    expect(out).toEqual({ results: [{ premium: 181 }] });
  });

  // Quoting — components
  it("a quote for a single component uses the per-component base premium", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune", enchantment: 1, cursed: false }] },
      ],
    });
    // 25 (rune base) × 1.10 (first contract) = 27.5 → ceil 28 + 5 fee = 33
    expect(out).toEqual({ results: [{ premium: 33 }] });
  });
  it.todo("a quote for three alike components uses the bundle premium of 60 G");

  // Quoting — per-item risk surcharges
  it.todo("cursed items add a 50% risk surcharge");
  it.todo("items with enchantment >= 5 add a 30% risk surcharge");

  // Quoting — customer-level adjustments
  it.todo("long-standing customers (>= 2 years with MHPCO) receive a 20% loyalty discount");
  it.todo("the first contract carries a 10% initial assessment surcharge");
  it.todo("each contract after the first receives a 15% discount");

  // Quoting — rounding
  it.todo("the premium is rounded up to whole G in MHPCO's favor");

  // Claims — basic
  it.todo("a claim subtracts a 100 G deductible from the damage amount");
  it.todo("the total payout per policy is capped at twice the insurance sum");
  it.todo("damage to items with enchantment >= 8 is reimbursed at 50%");
  it.todo("damage to dragon-material items is fully reimbursed");
  it.todo("remainingCap decreases across successive claims on the same policy");
});

