const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BUNDLE_PREMIUM = 60;
const COMPONENT_BUNDLE_SIZE = 3;

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE = 1.1;

const itemBasePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const itemsBasePremium = (items: Item[]): number => {
  const componentCounts: Record<string, number> = {};
  let total = 0;
  for (const item of items) {
    if (isComponent(item)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += itemBasePremium(item);
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    const bundles = Math.floor(count / COMPONENT_BUNDLE_SIZE);
    const singles = count % COMPONENT_BUNDLE_SIZE;
    total += bundles * COMPONENT_BUNDLE_PREMIUM + singles * (BASE_PREMIUM_BY_TYPE[type] ?? 0);
  }
  return total;
};

