// strips floating-point artifacts so a clean 110.0 stays 110.
const roundInFavor = (amount: number): number => Math.ceil(amount - 1e-9);

const quotePremium = (step: QuoteStep, _customer: Customer): QuoteResult => {
  const itemsSum = itemsBasePremium(step.items);
  const premium = roundInFavor(itemsSum * FIRST_CONTRACT_SURCHARGE) + PROCESSING_FEE;
  return { premium };
};

export const runScenario = (scenario: Scenario): ScenarioOutput => {
  const results: StepResult[] = scenario.steps.map((step) =>
    quotePremium(step as QuoteStep, scenario.customer),
  );
  return { results };
};

