      const policy = policies[step.policy];
      const damageSum = step.incident.damages.reduce((s, d) => s + d.amount, 0);
      const rawPayout = Math.max(damageSum - DEDUCTIBLE, 0);
      const payout = Math.min(rawPayout, policy.remainingCap);
      policy.remainingCap -= payout;
      results.push({ payout, remainingCap: policy.remainingCap });
    }
  }
  return { results };
};

