  const itemsSum = itemsBasePremium(step.items);
  const adjusted = itemsSum * contractAdjustmentFor(quoteIndex) * loyaltyFactor(customer);
  return { premium: roundInFavor(adjusted) + PROCESSING_FEE };
};

